// Preparar query GraphQL para Cults3D
const input = $input.first().json;
const query = input.query || '';
const limit = input.limit || 5;

return {
  graphqlBody: {
    query: `{
  creations(
    limit: ${limit},
    query: "${query.replace(/"/g, '\\"')}",
    free: true
  ) {
    id
    name
    description
    imageUrls
    fileUrls
    tagNames
    viewsCount
    creationLikesCount
    madeWithAi
    creator {
      nick
    }
  }
}`
  },
  originalQuery: query
};

// Normalizar respuesta de Cults3D al formato RenderHub
const response = $input.first().json;
const items = response?.data?.creations || [];
const query = $('Build GraphQL Query').first().json.originalQuery || '';

const BASE_URL = 'https://cults3d.com/en/3d-model/';

const normalized = items.map(item => {
  const thumbnail = (item.imageUrls || [])[0] || '';
  const tags = (item.tagNames || []).slice(0, 8);

  return {
    platform: 'Cults3D',
    id: String(item.id),
    name: item.name || '',
    description: (item.description || '').replace(/<[^>]*>/g, '').slice(0, 300),
    thumbnail_url: thumbnail,
    page_url: `${BASE_URL}${item.id}`,
    download_url: null,
    stl_direct: false,
    api_note: 'Cults3D API solo entrega metadata. Descarga en página web.',
    ai_generated: item.madeWithAi || false,
    creator: item.creator?.nick || '',
    likes: item.creationLikesCount || 0,
    views: item.viewsCount || 0,
    tags
  };
});

return {
  platform: 'Cults3D',
  query,
  count: normalized.length,
  results: normalized
};

meta.notes:
INPUT esperado: { query: string, limit?: number }
OUTPUT: { platform, query, count, results[] }
Credencial: Basic Auth - usuario = cults3d username, password = API Key
Generar API Key en: https://cults3d.com/en/api/keys
IMPORTANTE: La API de Cults3D solo entrega metadata/imágenes, NO archivos descargables.
